    private static readonly int[]    Roots     = [0, 15, 30, 45, 60, 75, 88, 103, 118, 131, 146, 161, 176, 191, 204, 217, 232, 247, 262, 275, 290, 303, 318, 331, 346, 361, 374, 389, 402, 415, 428, 443, 452, 467, 478, 491, 506, 517, 530, 545];

    // Left[node] == -1 means leaf node
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static double Eval(int node, ReadOnlySpan<double> f)
    {
        while (true)
        {
            if (Left[node] < 0)
                return Value[node];
            double v = f[Feature[node]];
            if (double.IsNaN(v))
                node = Missing[node];
            else if ((float)v < Threshold[node])
                node = Left[node];
            else
                node = Right[node];
        }
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static double PredictScore(ReadOnlySpan<double> f)
    {
        double s = BaseScore;
        for (int i = 0; i < TreeCount; i++)
            s += Eval(Roots[i], f);
        return s;
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static double PredictProbability(ReadOnlySpan<double> f)
    {
        double x = PredictScore(f);
        return x >= 0
            ? 1.0 / (1.0 + Math.Exp(-x))
            : Math.Exp(x) / (1.0 + Math.Exp(x));
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public static int Predict(ReadOnlySpan<double> f)
        => PredictProbability(f) >= 0.5 ? 1 : 0;
}
